import{_ as s,c as t,o as i,a1 as l}from"./chunks/framework.DILC4Csi.js";const h=JSON.parse('{"title":"Skill System Guide: Calling Rules, Priorities, and Skill Types Explained","description":"Learn Superpowers skill system core rules including the 1% principle, complete call flow, skill priority order, and the difference between rigid and flexible skills. This tutorial explains how to prevent AI agents from cutting corners and always follow best practices like TDD and systematic debugging. Master skill calling rules with practical examples and common error analysis to boost development efficiency.","frontmatter":{"title":"Skill System Guide: Calling Rules, Priorities, and Skill Types Explained","sidebarTitle":"Master Skill Calls","subtitle":"How to Use Skills: Calling Rules and Priorities","description":"Learn Superpowers skill system core rules including the 1% principle, complete call flow, skill priority order, and the difference between rigid and flexible skills. This tutorial explains how to prevent AI agents from cutting corners and always follow best practices like TDD and systematic debugging. Master skill calling rules with practical examples and common error analysis to boost development efficiency.","tags":["Skill System","Calling Rules","Workflow"],"prerequisite":["start-verification"],"order":50},"headers":[],"relativePath":"obra/superpowers/start/using-skills/index.md","filePath":"obra/superpowers/start/using-skills/index.md"}'),o={name:"obra/superpowers/start/using-skills/index.md"};function a(r,e,n,p,c,d){return i(),t("div",null,[...e[0]||(e[0]=[l(`<h1 id="how-to-use-skills-calling-rules-and-priorities" tabindex="-1">How to Use Skills: Calling Rules and Priorities <a class="header-anchor" href="#how-to-use-skills-calling-rules-and-priorities" aria-label="Permalink to &quot;How to Use Skills: Calling Rules and Priorities&quot;">​</a></h1><h2 id="what-you-ll-learn" tabindex="-1">What You&#39;ll Learn <a class="header-anchor" href="#what-you-ll-learn" aria-label="Permalink to &quot;What You&#39;ll Learn&quot;">​</a></h2><ul><li>Understand the core rules of the skill system (1% principle)</li><li>Master the correct timing and flow for skill calls</li><li>Learn skill priorities and know which skill to call first</li><li>Distinguish between rigid and flexible skills to avoid misuse</li></ul><hr><h2 id="your-current-dilemma" tabindex="-1">Your Current Dilemma <a class="header-anchor" href="#your-current-dilemma" aria-label="Permalink to &quot;Your Current Dilemma&quot;">​</a></h2><p>Do you feel like the AI agent is sometimes &quot;too smart&quot;?</p><ul><li>You ask a simple question, it gives an answer immediately, but it&#39;s incomplete</li><li>You ask it to fix a bug, it starts changing code right away, then introduces new issues</li><li>You want it to follow TDD, it says &quot;this is simple, no need for testing&quot;</li></ul><p><strong>These aren&#39;t &quot;smart&quot; behaviors—they&#39;re &quot;laziness&quot;</strong>—AI agents will try to accomplish tasks with the least effort.</p><p><strong>Superpowers&#39; Solution</strong>: Mandatory rules—even if there&#39;s only a 1% chance, you must check for skills.</p><hr><h2 id="when-to-use-this-approach" tabindex="-1">When to Use This Approach <a class="header-anchor" href="#when-to-use-this-approach" aria-label="Permalink to &quot;When to Use This Approach&quot;">​</a></h2><p><strong>Answer: Check unconditionally before every task.</strong></p><p>Specific scenarios:</p><ul><li>✅ Build new features</li><li>✅ Fix bugs</li><li>✅ Answer technical questions</li><li>✅ Refactor code</li><li>✅ Write tests</li><li>✅ Need to debug issues</li><li>✅ Explore codebase</li><li>✅ Collect information</li></ul><p><strong>Remember</strong>: Skill checks must be completed before any response or action, including before asking clarifying questions.</p><hr><h2 id="core-approach" tabindex="-1">Core Approach <a class="header-anchor" href="#core-approach" aria-label="Permalink to &quot;Core Approach&quot;">​</a></h2><h3 id="what-is-the-skill-system" tabindex="-1">What is the Skill System? <a class="header-anchor" href="#what-is-the-skill-system" aria-label="Permalink to &quot;What is the Skill System?&quot;">​</a></h3><p>The <strong>skill system</strong> is Superpowers&#39; core mechanism that requires AI agents to first check for applicable skills before any task.</p><p><strong>Mandatory Rules</strong>:</p><blockquote><p><strong>Even if there&#39;s only a 1% chance a skill applies, you must call it.</strong></p><p><strong>If a skill applies, you have no choice—you must use it.</strong></p><p><strong>This is not optional, not negotiable, and cannot be rationalized away.</strong></p></blockquote><h3 id="why-so-strict" tabindex="-1">Why So Strict? <a class="header-anchor" href="#why-so-strict" aria-label="Permalink to &quot;Why So Strict?&quot;">​</a></h3><p>Because AI agents have many ways to &quot;cut corners&quot;:</p><ul><li>&quot;This is simple, no need for a skill&quot; → Could become a complex problem in 5 minutes</li><li>&quot;Let me check the code first&quot; → But skills tell you how to check correctly</li><li>&quot;Let me gather information first&quot; → But skills tell you what information to gather</li></ul><p><strong>The skill system prevents all these lazy behaviors</strong>, ensuring AI agents always follow best practices.</p><hr><h2 id="follow-along" tabindex="-1">Follow Along <a class="header-anchor" href="#follow-along" aria-label="Permalink to &quot;Follow Along&quot;">​</a></h2><h3 id="step-1-understand-the-call-flow" tabindex="-1">Step 1: Understand the Call Flow <a class="header-anchor" href="#step-1-understand-the-call-flow" aria-label="Permalink to &quot;Step 1: Understand the Call Flow&quot;">​</a></h3><p>When an AI agent receives your task, it must follow this flow:</p><div class="language-mermaid vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">graph TD</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    A[&quot;Receive User Message&quot;] --&gt; B{Could any skill apply?}</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    B --&gt;|Yes, even just 1%| C[&quot;Call Skill tool&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    B --&gt;|Definitely not| H[&quot;Response including clarifying questions&quot;]</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    C --&gt; D[&quot;Announce: Using [skill] to [purpose]&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    D --&gt; E{Is there a checklist?}</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    E --&gt;|Yes| F[&quot;Create TodoWrite for each item&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    E --&gt;|No| G[&quot;Follow skill exactly&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    F --&gt; G</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    G --&gt; H</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    style B fill:#ffe5e5</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    style C fill:#e5ffe5</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    style D fill:#e5e5ff</span></span></code></pre></div><p><strong>Flow explanation</strong>:</p><ol><li><strong>Receive message</strong>: AI agent receives your task</li><li><strong>Check for skills</strong>: Determine if any skill might apply (even 1% possibility)</li><li><strong>Call skill</strong>: Use Skill tool to load skill content</li><li><strong>Announce usage</strong>: Clearly tell you &quot;Using [skill] to [purpose]&quot;</li><li><strong>Create task list</strong>: If the skill has a checklist, create a TodoWrite for each item</li><li><strong>Follow skill</strong>: Execute strictly according to skill instructions</li></ol><p><strong>Key points</strong>:</p><ul><li>Steps 2-3 must be completed before asking clarifying questions</li><li>Skill check must be completed before any action</li></ul><hr><h3 id="step-2-recognize-lazy-excuses" tabindex="-1">Step 2: Recognize &quot;Lazy Excuses&quot; <a class="header-anchor" href="#step-2-recognize-lazy-excuses" aria-label="Permalink to &quot;Step 2: Recognize &quot;Lazy Excuses&quot;&quot;">​</a></h3><p>AI agents might use various excuses to avoid calling skills. Recognizing these excuses ensures they don&#39;t cut corners.</p><p><strong>Common misconceptions vs. reality</strong>:</p><table tabindex="0"><thead><tr><th>AI&#39;s Thought</th><th>Reality</th></tr></thead><tbody><tr><td>&quot;This is just a simple question&quot;</td><td>A question is still a task. Check skills.</td></tr><tr><td>&quot;I need more context&quot;</td><td>Skill check comes before clarifying questions.</td></tr><tr><td>&quot;Let me check the code first&quot;</td><td>Skills tell you how to explore code. Check skills first.</td></tr><tr><td>&quot;I can quickly check git or files&quot;</td><td>Files lack conversation context. Check skills first.</td></tr><tr><td>&quot;Let me gather information first&quot;</td><td>Skills tell you how to gather information. Check skills first.</td></tr><tr><td>&quot;No formal skill needed&quot;</td><td>If a skill exists, use it.</td></tr><tr><td>&quot;I remember this skill&quot;</td><td>Skills evolve. Read the current version.</td></tr><tr><td>&quot;This isn&#39;t a task&quot;</td><td>Any action = task. Check skills.</td></tr><tr><td>&quot;Skill is too complex&quot;</td><td>Simple things can become complex. Use the skill.</td></tr><tr><td>&quot;Let me do this one thing first&quot;</td><td>Before doing anything, check skills first.</td></tr><tr><td>&quot;This feels efficient&quot;</td><td>Undisciplined action wastes time. Skills prevent this.</td></tr><tr><td>&quot;I know what this means&quot;</td><td>Knowing concept ≠ using skill. Call it.</td></tr></tbody></table><p><strong>If the AI agent says these things, immediately require it to check for skills.</strong></p><hr><h3 id="step-3-understand-skill-priorities" tabindex="-1">Step 3: Understand Skill Priorities <a class="header-anchor" href="#step-3-understand-skill-priorities" aria-label="Permalink to &quot;Step 3: Understand Skill Priorities&quot;">​</a></h3><p>When multiple skills might apply, use this priority order:</p><p><strong>1. Process Skills First</strong></p><p>Determine how to handle the task first:</p><ul><li><strong>brainstorming</strong> (creative design)—requires clarifying requirements</li><li><strong>systematic-debugging</strong> (systematic debugging)—requires fixing bugs</li></ul><p><strong>2. Implementation Skills Second</strong></p><p>Determine implementation approach (examples may vary by project version):</p><ul><li><strong>test-driven-development</strong> (TDD)</li><li>Other implementation-related skills</li></ul><p><strong>Examples</strong>:</p><ul><li>&quot;Let&#39;s build X&quot; → brainstorming first (design), then implementation skills</li><li>&quot;Fix this bug&quot; → systematic-debugging first (debugging), then domain-specific skills</li></ul><p><strong>Principle</strong>: First figure out how to do it (process), then do it (implementation).</p><hr><h3 id="step-4-distinguish-rigid-and-flexible-skills" tabindex="-1">Step 4: Distinguish Rigid and Flexible Skills <a class="header-anchor" href="#step-4-distinguish-rigid-and-flexible-skills" aria-label="Permalink to &quot;Step 4: Distinguish Rigid and Flexible Skills&quot;">​</a></h3><p>Not all skills are equally strict.</p><p><strong>Rigid Skills</strong>:</p><p>Must be followed exactly—don&#39;t adjust the discipline:</p><ul><li><strong>test-driven-development</strong> (TDD)</li><li><strong>systematic-debugging</strong> (systematic debugging)</li></ul><p>The core of these skills is strict process and discipline—changing the discipline defeats the purpose.</p><p><strong>Flexible Skills</strong>:</p><p>Adjust principles based on context:</p><ul><li><strong>brainstorming</strong> (creative design)</li><li><strong>writing-plans</strong> (writing plans)</li></ul><p>Skill content will reflect this distinction.</p><p><strong>Principle</strong>: Rigid skills must be strictly followed, flexible skills can be flexibly applied.</p><hr><h3 id="step-5-practical-exercise" tabindex="-1">Step 5: Practical Exercise <a class="header-anchor" href="#step-5-practical-exercise" aria-label="Permalink to &quot;Step 5: Practical Exercise&quot;">​</a></h3><p>Now that you understand the rules, let&#39;s see how an AI agent should behave.</p><p><strong>Scenario</strong>: You say &quot;Write me a user registration feature&quot;</p><p><strong>Wrong Approach</strong> (Lazy):</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>AI: Okay, I&#39;ll write the registration feature...</span></span>
<span class="line"><span>[Starts writing code directly]</span></span></code></pre></div><p><strong>Correct Approach</strong> (Following Skills):</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>AI: Let me check if there are applicable skills.</span></span>
<span class="line"><span>[Call brainstorming skill]</span></span>
<span class="line"><span></span></span>
<span class="line"><span>AI: Using brainstorming to clarify requirements for the user registration feature.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Now, let me ask a few questions to understand your requirements:</span></span>
<span class="line"><span>1. What fields are needed?</span></span>
<span class="line"><span>2. Is email verification required?</span></span>
<span class="line"><span>3. What are the password requirements?</span></span>
<span class="line"><span>[Wait for your answer]</span></span></code></pre></div><p><strong>Difference</strong>:</p><ul><li>Wrong approach: Starts directly, might get it wrong</li><li>Correct approach: Ask first to ensure requirements are met</li></ul><hr><h2 id="checkpoints" tabindex="-1">Checkpoints <a class="header-anchor" href="#checkpoints" aria-label="Permalink to &quot;Checkpoints&quot;">​</a></h2><p>Confirm the AI agent&#39;s behavior meets these checkpoints:</p><ul><li>[ ] Before starting a task, AI says &quot;Let me check for skills&quot;</li><li>[ ] Even for simple tasks, AI checks for skills</li><li>[ ] AI doesn&#39;t start action before asking clarifying questions</li><li>[ ] When multiple skills apply, AI calls them in priority order</li><li>[ ] Rigid skills (TDD, debugging) are executed strictly according to process</li><li>[ ] AI clearly tells you &quot;Using [skill] to [purpose]&quot;</li></ul><p>If all are OK, the AI agent is already following skill calling rules!</p><hr><h2 id="pitfall-alerts" tabindex="-1">Pitfall Alerts <a class="header-anchor" href="#pitfall-alerts" aria-label="Permalink to &quot;Pitfall Alerts&quot;">​</a></h2><h3 id="ai-says-it-needs-more-context" tabindex="-1">AI Says It Needs More Context <a class="header-anchor" href="#ai-says-it-needs-more-context" aria-label="Permalink to &quot;AI Says It Needs More Context&quot;">​</a></h3><p><strong>Symptom</strong>: AI says &quot;I need more information to start&quot;</p><p><strong>Problem</strong>: Skill check should come before clarifying questions</p><p><strong>Solution</strong>:</p><ul><li>Clearly tell AI: &quot;Before asking questions, check skills first&quot;</li><li>Skills might tell you what information needs to be collected</li></ul><h3 id="ai-says-task-is-simple" tabindex="-1">AI Says Task Is Simple <a class="header-anchor" href="#ai-says-task-is-simple" aria-label="Permalink to &quot;AI Says Task Is Simple&quot;">​</a></h3><p><strong>Symptom</strong>: AI says &quot;This is simple, no need for skills&quot;</p><p><strong>Problem</strong>: Simple tasks might also need workflows</p><p><strong>Solution</strong>:</p><ul><li>Remind AI: &quot;Even if there&#39;s a 1% possibility, you must check for skills&quot;</li><li>Simple tasks often become complex during the process, skills prevent this</li></ul><h3 id="ai-says-it-remembers-skills" tabindex="-1">AI Says It Remembers Skills <a class="header-anchor" href="#ai-says-it-remembers-skills" aria-label="Permalink to &quot;AI Says It Remembers Skills&quot;">​</a></h3><p><strong>Symptom</strong>: AI says &quot;I know what TDD is, no need to call skills&quot;</p><p><strong>Problem</strong>: Skills evolve, memory might be outdated</p><p><strong>Solution</strong>:</p><ul><li>Require AI: &quot;Use Skill tool to call the latest version of the skill&quot;</li><li>Skill files might be updated, AI needs to read the latest version</li></ul><hr><h2 id="lesson-summary" tabindex="-1">Lesson Summary <a class="header-anchor" href="#lesson-summary" aria-label="Permalink to &quot;Lesson Summary&quot;">​</a></h2><p>In this lesson you learned:</p><ol><li><strong>Core Rule</strong>: Even if there&#39;s only a 1% possibility, you must call skills</li><li><strong>Call Flow</strong>: Receive message → Check skills → Call Skill tool → Announce usage → Follow skills</li><li><strong>Common Excuses</strong>: Recognize AI&#39;s &quot;lazy&quot; thoughts, prevent skill evasion</li><li><strong>Skill Priorities</strong>: Process skills (brainstorming, debugging) first, implementation skills second</li><li><strong>Skill Types</strong>: Rigid skills (TDD, debugging) strictly followed, flexible skills flexibly applied</li></ol><p><strong>Core Ideas</strong>:</p><ul><li>Skill system prevents AI agents from cutting corners</li><li>Mandatory rules ensure best practices are always followed</li><li>Skill check must be completed before any action</li></ul><hr><h2 id="coming-next" tabindex="-1">Coming Next <a class="header-anchor" href="#coming-next" aria-label="Permalink to &quot;Coming Next&quot;">​</a></h2><blockquote><p>In the next lesson, we&#39;ll learn about the <strong><a href="./../../platforms/claude-code/">Claude Code Platform</a></strong>.</p><p>You&#39;ll learn:</p><ul><li>Complete Claude Code integration approach</li><li>How to use the Skill tool to call skills</li><li>Automatic loading mechanism of the hook system</li></ul></blockquote><hr><h2 id="appendix-source-code-reference" tabindex="-1">Appendix: Source Code Reference <a class="header-anchor" href="#appendix-source-code-reference" aria-label="Permalink to &quot;Appendix: Source Code Reference&quot;">​</a></h2><details><summary><strong>Click to expand source code locations</strong></summary><blockquote><p>Updated: 2026-02-01</p></blockquote><table tabindex="0"><thead><tr><th>Function</th><th>File Path</th><th>Line</th></tr></thead><tbody><tr><td>Core rule definition</td><td><a href="https://github.com/obra/superpowers/blob/main/skills/using-superpowers/SKILL.md#L6-L12" target="_blank" rel="noreferrer"><code>skills/using-superpowers/SKILL.md</code></a></td><td>6-12</td></tr><tr><td>Skill tool invocation</td><td><a href="https://github.com/obra/superpowers/blob/main/skills/using-superpowers/SKILL.md#L16" target="_blank" rel="noreferrer"><code>skills/using-superpowers/SKILL.md</code></a></td><td>16</td></tr><tr><td>Call flow diagram</td><td><a href="https://github.com/obra/superpowers/blob/main/skills/using-superpowers/SKILL.md#L26-L46" target="_blank" rel="noreferrer"><code>skills/using-superpowers/SKILL.md</code></a></td><td>26-46</td></tr><tr><td>Red Flags (lazy excuses)</td><td><a href="https://github.com/obra/superpowers/blob/main/skills/using-superpowers/SKILL.md#L48-L65" target="_blank" rel="noreferrer"><code>skills/using-superpowers/SKILL.md</code></a></td><td>48-65</td></tr><tr><td>Skill priority rules</td><td><a href="https://github.com/obra/superpowers/blob/main/skills/using-superpowers/SKILL.md#L67-L76" target="_blank" rel="noreferrer"><code>skills/using-superpowers/SKILL.md</code></a></td><td>67-76</td></tr><tr><td>Rigid/flexible skill distinction</td><td><a href="https://github.com/obra/superpowers/blob/main/skills/using-superpowers/SKILL.md#L77-L81" target="_blank" rel="noreferrer"><code>skills/using-superpowers/SKILL.md</code></a></td><td>77-81</td></tr><tr><td>User instruction explanation</td><td><a href="https://github.com/obra/superpowers/blob/main/skills/using-superpowers/SKILL.md#L85-L88" target="_blank" rel="noreferrer"><code>skills/using-superpowers/SKILL.md</code></a></td><td>85-88</td></tr></tbody></table><p><strong>Key constants</strong>:</p><ul><li><strong>1% principle</strong>: Must call skill even if only 1% possibility (<code>L7</code>)</li></ul><p><strong>Key rules</strong>:</p><ul><li><strong>Mandatory rule</strong>: If a skill applies, AI must use it, not negotiable (<code>L9-L12</code>)</li><li><strong>Process first</strong>: Process skills (brainstorming, debugging) → Implementation skills (<code>L71-L75</code>)</li></ul></details>`,108)])])}const g=s(o,[["render",a]]);export{h as __pageData,g as default};
